642→    private fun <T> Sequence<Callable<T>>.parallel(
643→        cb: (T) -> Unit,
644→        numberOfThreads: Int = Runtime.getRuntime().availableProcessors(),
645→    ) {
646→        val pill = object : Future<T> {
647→            override fun isDone(): Boolean {
648→                throw UnsupportedOperationException()
649→            }
650→
651→            override fun get(timeout: Long, unit: TimeUnit): T {
652→                throw UnsupportedOperationException()
653→            }
654→
655→            override fun get(): T {
656→                throw UnsupportedOperationException()
657→            }
658→
659→            override fun cancel(mayInterruptIfRunning: Boolean): Boolean {
660→                throw UnsupportedOperationException()
661→            }
662→
663→            override fun isCancelled(): Boolean {
664→                throw UnsupportedOperationException()
665→            }
666→        }
667→        val q = ArrayBlockingQueue<Future<T>>(numberOfThreads)
668→        val producer = thread(start = true) {
669→            val executorService = Executors.newCachedThreadPool()
670→            try {
671→                for (task in this) {
672→                    q.put(executorService.submit(task))
673→                }
674→                q.put(pill)
675→            } catch (e: InterruptedException) {
676→                // we've been asked to stop consuming sequence
677→            } finally {
678→                executorService.shutdown()
679→            }
680→        }
681→        try {
682→            while (true) {
683→                val result = q.take()
684→                if (result != pill) cb(result.get()) else break
685→            }
686→        } finally {
687→            producer.interrupt() // in case q.take()/result.get() throws
688→            producer.join()
689→        }
690→    }
