 60→    private fun ASTNode?.doesNotRequirePreSemi(): Boolean {
 61→        if (this == null) {
 62→            return true
 63→        }
 64→        if (this is PsiWhiteSpace) {
 65→            val nextLeaf = nextLeaf {
 66→                val psi = it.psi
 67→                it !is PsiWhiteSpace && it !is PsiComment && psi.getStrictParentOfType<KDoc>() == null &&
 68→                    psi.getStrictParentOfType<KtAnnotationEntry>() == null
 69→            }
 70→            return (
 71→                nextLeaf == null || // \s+ and then eof
 72→                    textContains('\n') && nextLeaf.elementType != KtTokens.LBRACE
 73→                )
 74→        }
 75→        return false
 76→    }
 77→
 78→    private fun isNoSemicolonRequiredAfter(node: ASTNode): Boolean {
 79→        val prevCodeLeaf =
 80→            node.prevCodeLeaf()
 81→                ?: return true
 82→        if (prevCodeLeaf.elementType == OBJECT_KEYWORD) {
 83→            // https://github.com/pinterest/ktlint/issues/281
 84→            return false
 85→        }
 86→
 87→        val parent = prevCodeLeaf.treeParent?.psi
 88→        if (parent is KtLoopExpression && parent !is KtDoWhileExpression && parent.body == null) {
 89→            // https://github.com/pinterest/ktlint/issues/955
 90→            return false
 91→        }
 92→        if (parent is KtIfExpression && parent.then == null) {
 93→            return false
 94→        }
 95→        // In case of an enum entry the semicolon (e.g. the node) is a direct child node of enum entry
 96→        if (node.treeParent.elementType == ENUM_ENTRY) {
 97→            return node.isLastCodeLeafBeforeClosingOfClassBody()
 98→        }
 99→
100→        // After formatting an enum class in which the last enum entry is terminated by a semicolon, the semicolon might
101→        // have been moved outside the enum entry. When that semicolon terminates the enum entries list, it should not be
102→        // removed unless it is redundant (i.e. it is the last code leaf before the closing brace of the enum class).
103→        if (node.treeParent.elementType == CLASS_BODY && node.isEnumEntriesTerminatingSemicolon()) {
104→            return node.isLastCodeLeafBeforeClosingOfClassBody()
105→        }
106→
107→        return true
108→    }
109→
110→    private fun ASTNode?.isLastCodeLeafBeforeClosingOfClassBody() =
111→        getLastCodeLeafBeforeClosingOfClassBody() == this
112→
113→    private fun ASTNode?.getLastCodeLeafBeforeClosingOfClassBody() =
114→        this
115→            ?.parent(CLASS_BODY)
116→            ?.lastChildLeafOrSelf()
117→            ?.prevCodeLeaf()
118→
119→    private fun ASTNode.isEnumEntriesTerminatingSemicolon(): Boolean {
120→        val classBody = parent(CLASS_BODY) ?: return false
121→        val lastEnumEntry = classBody.getChildren(null).lastOrNull { it.elementType == ENUM_ENTRY } ?: return false
122→
123→        var candidate = lastEnumEntry.lastChildLeafOrSelf().nextCodeLeaf()
124→        while (candidate != null && candidate.elementType == COMMA) {
125→            candidate = candidate.nextCodeLeaf()
126→        }
127→        return candidate == this
128→    }
129→}
