{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/EnumTrailingCommaWithMemberDeclarationsFormattingTest.kt","content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.core.Code
import com.pinterest.ktlint.core.KtLintRuleEngine
import com.pinterest.ktlint.core.LintError
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test

class EnumTrailingCommaWithMemberDeclarationsFormattingTest {
    @Test
    fun `Given an enum with member declarations and missing trailing comma then ktlint format should not report uncorrected errors`() {
        val code =
            """
            enum class TestEnum() {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()

        val expectedFormattedCode =
            """
            enum class TestEnum() {
                A,
                B,
                ;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()

        val ruleProviders = StandardRuleSetProvider().getRuleProviders()
        val ruleEngine = KtLintRuleEngine(ruleProviders = ruleProviders)

        val lintErrorsWithCorrectionInfo = mutableListOf<Pair<LintError, Boolean>>()
        val formattedCode =
            ruleEngine.format(Code.CodeSnippet(code)) { lintError, corrected ->
                lintErrorsWithCorrectionInfo.add(lintError to corrected)
            }

        val uncorrectedErrors = lintErrorsWithCorrectionInfo.filter { !it.second }.map { it.first }
        assertThat(uncorrectedErrors)
            .describedAs(
                "Ktlint should not report uncorrected errors after formatting. " +
                    "Reported errors were: ${lintErrorsWithCorrectionInfo.joinToString { \"${it.first.ruleId} (corrected=${it.second})\" }}",
            )
            .isEmpty()
        assertThat(formattedCode).isEqualTo(expectedFormattedCode)
    }
}
